import * as React from "react";

export type PipelinePhase = "preclinical" | "phase1" | "phase2" | "phase3" | "approved";

export interface PipelineRow {
  drug: string;
  indication: string;
  phase: PipelinePhase;
  note?: string;
}

export interface TdPipelineTableProps {
  rows: PipelineRow[];
  className?: string;
}

const PHASE_ORDER: PipelinePhase[] = [
  "preclinical",
  "phase1",
  "phase2",
  "phase3",
  "approved",
];

const PHASE_LABEL: Record<PipelinePhase, string> = {
  preclinical: "Preclinical",
  phase1: "Phase 1",
  phase2: "Phase 2",
  phase3: "Phase 3",
  approved: "Approved",
};

function phaseProgress(phase: PipelinePhase): number {
  const idx = PHASE_ORDER.indexOf(phase);
  return ((idx + 1) / PHASE_ORDER.length) * 100;
}

export function TdPipelineTable({ rows, className = "" }: TdPipelineTableProps) {
  return (
    <div
      className={`w-full overflow-hidden rounded-xl border ${className}`.trim()}
      style={{ borderColor: "var(--td-border, rgba(15,23,42,0.08))" }}
    >
      <div className="hidden grid-cols-[2fr_2fr_3fr] gap-4 bg-slate-50 px-6 py-3 text-xs font-semibold uppercase tracking-[0.18em] text-slate-500 md:grid">
        <span>Program</span>
        <span>Indication</span>
        <span>Status</span>
      </div>
      <ul className="flex flex-col divide-y divide-slate-100">
        {rows.map((row) => (
          <li
            key={row.drug}
            className="grid grid-cols-1 gap-3 px-6 py-5 md:grid-cols-[2fr_2fr_3fr] md:items-center md:gap-4"
          >
            <div>
              <div className="text-base font-semibold text-slate-900">{row.drug}</div>
              {row.note ? <div className="text-xs text-slate-500">{row.note}</div> : null}
            </div>
            <div className="text-sm text-slate-700">{row.indication}</div>
            <div className="flex flex-col gap-2">
              <div
                className="h-2 w-full overflow-hidden rounded-full"
                style={{ backgroundColor: "var(--td-track, rgba(15,23,42,0.08))" }}
              >
                <div
                  className="h-full rounded-full transition-[width]"
                  style={{
                    width: `${phaseProgress(row.phase)}%`,
                    backgroundColor: "var(--td-primary, #2E6554)",
                  }}
                />
              </div>
              <div
                className="text-xs font-medium uppercase tracking-[0.18em]"
                style={{ color: "var(--td-secondary, #234F98)" }}
              >
                {PHASE_LABEL[row.phase]}
              </div>
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default TdPipelineTable;
